 1→const BASE_URL = process.env.NEXT_PUBLIC_API_URL ?? 'http://localhost:8000';
 2→
 3→async function apiFetch(path: string, options?: RequestInit) {
 4→  const res = await fetch(`${BASE_URL}${path}`, options);
 5→  if (!res.ok) throw new Error(`API error ${res.status}`);
 6→  return res.json();
 7→}
 8→
 9→export async function listProjects() {
10→  return apiFetch('/api/v1/projects');
11→}
12→
13→export async function createProject(name: string, type: string) {
14→  return apiFetch('/api/v1/projects', {
15→    method: 'POST',
16→    headers: { 'Content-Type': 'application/json', 'x-role': 'lawyer' },
17→    body: JSON.stringify({ name, type }),
18→  });
19→}
20→
21→export async function getDocument(id: number) {
22→  return apiFetch(`/api/v1/documents/${id}`);
23→}
24→
25→export async function exportMd(id: number): Promise<string> {
26→  const res = await fetch(`${BASE_URL}/api/v1/documents/${id}/export/md`, { method: 'POST' });
27→  return res.text();
28→}
