 1→'use client';
 2→import { useState } from 'react';
 3→import { startWorkflow } from '@/lib/api';
 4→
 5→const TEMPLATES = [
 6→  { value: 'legal-text-format', label: '法律文本格式化' },
 7→  { value: 'legal-qa-extractor', label: '问答提取' },
 8→  { value: 'litigation-analysis', label: '诉讼分析' },
 9→  { value: 'legal-proposal-generator', label: '方案书生成' },
10→];
11→
12→export default function WorkflowsPage() {
13→  const [template, setTemplate] = useState('legal-text-format');
14→  const [text, setText] = useState('');
15→  const [result, setResult] = useState<Record<string, unknown> | null>(null);
16→  const [loading, setLoading] = useState(false);
17→
18→  async function handleRun(e: React.FormEvent) {
19→    e.preventDefault();
20→    setLoading(true);
21→    try {
22→      const run = await startWorkflow(1, template, { text });
23→      setResult(run);
24→    } finally {
25→      setLoading(false);
26→    }
27→  }
28→
29→  return (
30→    <main style={{ padding: '2rem', fontFamily: 'sans-serif' }}>
31→      <h1>工作流触发</h1>
32→      <form onSubmit={handleRun} style={{ display: 'flex', flexDirection: 'column', gap: '0.75rem', maxWidth: '600px' }}>
33→        <select value={template} onChange={e => setTemplate(e.target.value)}>
34→          {TEMPLATES.map(t => <option key={t.value} value={t.value}>{t.label}</option>)}
35→        </select>
36→        <textarea
37→          value={text}
38→          onChange={e => setText(e.target.value)}
39→          placeholder="输入待处理文本..."
40→          rows={6}
41→          required
42→        />
43→        <button type="submit" disabled={loading}>
44→          {loading ? '执行中...' : '触发执行'}
45→        </button>
46→      </form>
47→      {result && (
48→        <div style={{ marginTop: '1.5rem' }}>
49→          <h2>执行结果</h2>
50→          <p>状态：{String(result.status)}</p>
51→          <pre style={{ background: '#f5f5f5', padding: '1rem', overflow: 'auto' }}>
52→            {JSON.stringify(result.results ?? result.error, null, 2)}
53→          </pre>
54→        </div>
55→      )}
56→    </main>
57→  );
58→}
