 1→'use client';
 2→import { useEffect, useState } from 'react';
 3→import { listKnowledge, createKnowledge } from '@/lib/api';
 4→
 5→type Item = { id: number; question: string; answer: string; tags: string[] };
 6→
 7→export default function KnowledgePage() {
 8→  const [items, setItems] = useState<Item[]>([]);
 9→  const [q, setQ] = useState('');
10→  const [question, setQuestion] = useState('');
11→  const [answer, setAnswer] = useState('');
12→  const [tags, setTags] = useState('');
13→
14→  async function handleSearch(e: React.FormEvent) {
15→    e.preventDefault();
16→    const data = await listKnowledge(q);
17→    setItems(data);
18→  }
19→
20→  async function handleCreate(e: React.FormEvent) {
21→    e.preventDefault();
22→    await createKnowledge(question, answer, tags.split(',').map(t => t.trim()).filter(Boolean));
23→    setQuestion(''); setAnswer(''); setTags('');
24→    const data = await listKnowledge(q);
25→    setItems(data);
26→  }
27→
28→  useEffect(() => { listKnowledge().then(setItems).catch(console.error); }, []);
29→
30→  return (
31→    <main style={{ padding: '2rem', fontFamily: 'sans-serif' }}>
32→      <h1>知识库</h1>
33→      <form onSubmit={handleSearch} style={{ display: 'flex', gap: '0.5rem', marginBottom: '1rem' }}>
34→        <input value={q} onChange={e => setQ(e.target.value)} placeholder="搜索问题或答案..." style={{ flex: 1 }} />
35→        <button type="submit">搜索</button>
36→      </form>
37→      <form onSubmit={handleCreate} style={{ display: 'flex', flexDirection: 'column', gap: '0.5rem', marginBottom: '1.5rem', maxWidth: '600px' }}>
38→        <input value={question} onChange={e => setQuestion(e.target.value)} placeholder="问题" required />
39→        <textarea value={answer} onChange={e => setAnswer(e.target.value)} placeholder="答案" rows={3} required />
40→        <input value={tags} onChange={e => setTags(e.target.value)} placeholder="标签（逗号分隔）" />
41→        <button type="submit">添加</button>
42→      </form>
43→      <ul style={{ listStyle: 'none', padding: 0 }}>
44→        {items.map(item => (
45→          <li key={item.id} style={{ borderBottom: '1px solid #eee', padding: '0.75rem 0' }}>
46→            <strong>Q: {item.question}</strong>
47→            <p style={{ margin: '0.25rem 0' }}>A: {item.answer}</p>
48→            <small style={{ color: '#888' }}>{item.tags.join(', ')}</small>
49→          </li>
50→        ))}
51→      </ul>
52→    </main>
53→  );
54→}
